_S3 = boto3.client("s3")
_DDB = boto3.client("dynamodb")
_SNS = boto3.client("sns")
_SQS = boto3.client("sqs")


def _env(name: str, default: str = "") -> str:
    v = os.environ.get(name, default)
    return v if v is not None else default


def _json_response(status_code: int, body: dict):
    return {
        "statusCode": status_code,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(body, separators=(",", ":"), default=str),
    }


def handler(event, context):
    """
    Generic microservice Lambda entrypoint.
    Demonstrates using shared permissions across S3/DynamoDB/SNS/SQS.

    Configure via env vars:
      S3_BUCKET
      S3_KEY_PREFIX
      DDB_TABLE
      SNS_TOPIC_ARN
      SQS_QUEUE_URL
    """
    bucket = _env("S3_BUCKET")
    key_prefix = _env("S3_KEY_PREFIX", "events/")
    table = _env("DDB_TABLE")
    topic_arn = _env("SNS_TOPIC_ARN")
    queue_url = _env("SQS_QUEUE_URL")

    req_id = getattr(context, "aws_request_id", None) or "unknown"
    payload = {
        "requestId": req_id,
        "event": event,
    }

    actions = []

    try:
        if bucket:
            key = f"{key_prefix.rstrip('/')}/{req_id}.json"
            _S3.put_object(
                Bucket=bucket,
                Key=key,
                Body=json.dumps(payload).encode("utf-8"),
                ContentType="application/json",
            )
            actions.append({"s3PutObject": {"bucket": bucket, "key": key}})

        if table:
            item = {
                "pk": {"S": f"REQ#{req_id}"},
                "sk": {"S": "META"},
                "requestId": {"S": req_id},
                "createdAt": {"S": str(getattr(context, "invoked_function_arn", ""))},
            }
            _DDB.put_item(TableName=table, Item=item)
            actions.append({"dynamoPutItem": {"table": table, "pk": item["pk"]["S"]}})

        if topic_arn:
            resp = _SNS.publish(
                TopicArn=topic_arn,
                Message=json.dumps(payload, separators=(",", ":")),
                Subject="microservice-event",
            )
            actions.append({"snsPublish": {"topicArn": topic_arn, "messageId": resp.get("MessageId")}})

        if queue_url:
            resp = _SQS.send_message(
                QueueUrl=queue_url,
                MessageBody=json.dumps(payload, separators=(",", ":")),
            )
            actions.append({"sqsSendMessage": {"queueUrl": queue_url, "messageId": resp.get("MessageId")}})

        return _json_response(
            200,
            {
                "ok": True,
                "requestId": req_id,
                "actions": actions,
            },
        )

    except ClientError as e:
        return _json_response(
            500,
            {
                "ok": False,
                "requestId": req_id,
                "error": {
                    "type": "ClientError",
                    "message": str(e),
                    "code": (e.response.get("Error", {}) or {}).get("Code"),
                },
                "actions": actions,
            },
        )
    except Exception as e:
        return _json_response(
            500,
            {
                "ok": False,
                "requestId": req_id,
                "error": {"type": type(e).__name__, "message": str(e)},
                "actions": actions,
            },
        )